122	// ---------------------------------------------------------------------------
123	// Assertion 1 — Completeness
124	//
125	// "Every (state, event) pair in this document has a defined row.
126	//  Completeness test iterates the cartesian product and fails on any
127	//  missing pair."
128	// ---------------------------------------------------------------------------
129	
130	describe('assertion-1: completeness — every documented pair has a defined TRANSITIONS row', () => {
131	  it('all documented non-abandoned pairs return a defined result from transition()', () => {
132	    for (const [state, event] of DOCUMENTED_NON_ABANDONED_PAIRS) {
133	      expect(
134	        transition(state, event),
135	        `(${state}, ${event}) is documented but missing from TRANSITIONS`,
136	      ).toBeDefined();
137	    }
138	  });
