140	  it('abandoned handles every event (absorbing terminal state — complete cartesian coverage)', () => {
141	    for (const e of ALL_EVENTS) {
142	      expect(
143	        transition('abandoned', e),
144	        `(abandoned, ${e}) must be defined`,
145	      ).toBeDefined();
146	    }
147	  });
148	
149	  it('undocumented non-abandoned pairs return undefined (no phantom rows)', () => {
150	    const documentedSet = new Set(
151	      DOCUMENTED_NON_ABANDONED_PAIRS.map(([s, e]) => `${s}:${e}`),
152	    );
153	    for (const s of ALL_STATES) {
154	      if (s === 'abandoned') continue;
155	      for (const e of ALL_EVENTS) {
156	        const key = `${s}:${e}`;
157	        if (documentedSet.has(key)) continue;
158	        expect(
159	          transition(s, e),
160	          `(${s}, ${e}) is not documented but has a TRANSITIONS row`,
161	        ).toBeUndefined();
162	      }
163	    }
164	  });
165	});
