167	// ---------------------------------------------------------------------------
168	// Assertion 2 — All to-states are valid State values
169	//
170	// "No `from → to` row targets a state not in the state enum."
171	// ---------------------------------------------------------------------------
172	
173	describe('assertion-2: no to-state outside the State enum', () => {
174	  it('every outcome target in every transition row is a member of State', () => {
175	    const validStates = new Set<string>(ALL_STATES);
176	    for (const s of ALL_STATES) {
177	      const row = TRANSITIONS[s];
178	      for (const e of ALL_EVENTS) {
179	        const result = row[e];
180	        if (result === undefined) continue;
181	        for (const target of allTargets(result)) {
182	          expect(validStates, `to="${target}" from (${s},${e}) is not a valid State`).toContain(target);
183	        }
184	      }
185	    }
186	  });
187	});
