189	// ---------------------------------------------------------------------------
190	// Assertion 3 — pending → ready guard requires all deps complete
191	//
192	// "`pending → ready` triggers only when all depends_on are `complete`;
193	//  mixed states leave item in `pending`."
194	// ---------------------------------------------------------------------------
195	
196	describe('assertion-3: pending → ready requires all depends_on complete', () => {
197	  it('deps_satisfied outcome targeting ready has a guard mentioning complete deps', () => {
198	    const result = transition('pending', 'deps_satisfied') as ConditionalTransitionResult;
199	    expect(result.kind).toBe('conditional');
200	    const readyOutcome = result.outcomes.find(o => o.to === 'ready');
201	    expect(readyOutcome).toBeDefined();
202	    // The guard must reference the completeness condition
203	    expect(readyOutcome!.guard).toMatch(/complete/i);
204	    expect(readyOutcome!.guard).toMatch(/depends_on/i);
205	  });
206	
207	  it('deps_satisfied does not target ready unconditionally (mixed states stay pending)', () => {
208	    // The transition is conditional, not direct — Engine evaluates the guard
209	    const result = transition('pending', 'deps_satisfied');
210	    expect(result?.kind).toBe('conditional');
211	    // A direct (unconditional) result would bypass the guard; conditional is required.
212	  });
213	
214	  it('pending has no other events that advance state (only deps_satisfied and user_cancel)', () => {
215	    const definedEvents = ALL_EVENTS.filter(e => transition('pending', e) !== undefined);
216	    expect(definedEvents.sort()).toEqual(['deps_satisfied', 'user_cancel'].sort());
217	  });
218	});
