246	    // and bootstrapping→bootstrap_ok has 'emit phase_start' — both are internal Engine actions.
247	    const readyResult = transition('ready', 'phase_start') as ConditionalTransitionResult;
248	    const bootstrappingOutcome = readyResult.outcomes.find(o => o.to === 'bootstrapping');
249	    expect(bootstrappingOutcome?.sideEffects).toContain('invoke Worktree Manager.create');
250	
